import { GoogleGenAI } from "@google/genai";

export class GeminiService {
  private ai: GoogleGenAI;

  constructor() {
    this.ai = new GoogleGenAI({ apiKey: process.env.API_KEY || '' });
  }

  async getCareerAdvice(userQuery: string, language: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `User asks: ${userQuery}. Provide career advice for working in Europe. Respond in ${language}. Keep it concise and professional.`,
        config: {
          systemInstruction: "You are a professional HR consultant for IMKON, an agency helping Uzbek citizens find jobs in Europe. Be encouraging but realistic about visa requirements and skills needed."
        }
      });
      return response.text;
    } catch (error) {
      console.error("Gemini Error:", error);
      return "Kechirasiz, hozirgi vaqtda maslahat bera olmayman. / Извините, сейчас я не могу дать совет. / Sorry, I can't provide advice right now.";
    }
  }

  async summarizeJob(jobTitle: string, requirements: string[], language: string) {
    try {
      const response = await this.ai.models.generateContent({
        model: 'gemini-3-flash-preview',
        contents: `Job Title: ${jobTitle}. Requirements: ${requirements.join(', ')}. Summarize why this is a good opportunity in 2 sentences in ${language}.`,
      });
      return response.text;
    } catch (error) {
      return "";
    }
  }
}

export const geminiService = new GeminiService();

import React, { useState, useEffect } from 'react';
import { Link, useLocation } from 'react-router-dom';
import { Menu, X, Globe, Phone } from 'lucide-react';
import { Language } from '../types';
import { TRANSLATIONS } from '../constants';

interface NavbarProps {
  lang: Language;
  setLang: (l: Language) => void;
}

const Navbar: React.FC<NavbarProps> = ({ lang, setLang }) => {
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();
  const t = TRANSLATIONS[lang];

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navItems = [
    { name: t.nav.home, path: '/' },
    { name: t.nav.jobs, path: '/jobs' },
    { name: t.nav.about, path: '/about' },
    { name: t.nav.partners, path: '/partners' },
    { name: t.nav.contact, path: '/contact' },
  ];

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${scrolled ? 'bg-white/90 backdrop-blur-md shadow-sm py-3' : 'bg-transparent py-5'}`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          <Link to="/" className="flex items-center space-x-2">
            <span className={`text-2xl font-display font-extrabold tracking-tighter ${scrolled ? 'text-indigo-900' : 'text-indigo-800'}`}>IMKON</span>
          </Link>

          {/* Desktop Nav */}
          <div className="hidden md:flex items-center space-x-8">
            {navItems.map((item) => (
              <Link 
                key={item.path} 
                to={item.path}
                className={`text-sm font-medium transition-colors hover:text-indigo-600 ${location.pathname === item.path ? 'text-indigo-600' : 'text-slate-600'}`}
              >
                {item.name}
              </Link>
            ))}
          </div>

          <div className="hidden md:flex items-center space-x-4">
            <div className="flex items-center space-x-2 border-r pr-4 border-slate-200">
              <Globe className="w-4 h-4 text-slate-400" />
              {(['UZ', 'RU', 'EN'] as Language[]).map((l) => (
                <button
                  key={l}
                  onClick={() => setLang(l)}
                  className={`text-xs font-bold px-1.5 py-0.5 rounded ${lang === l ? 'bg-indigo-600 text-white' : 'text-slate-500 hover:bg-slate-100'}`}
                >
                  {l}
                </button>
              ))}
            </div>
            <Link to="/apply" className="bg-indigo-600 text-white px-5 py-2 rounded-full text-sm font-semibold hover:bg-indigo-700 transition-all shadow-lg shadow-indigo-200">
              {t.nav.apply}
            </Link>
          </div>

          {/* Mobile toggle */}
          <div className="md:hidden flex items-center space-x-4">
            <button onClick={() => setIsOpen(!isOpen)} className="text-slate-600">
              {isOpen ? <X className="w-6 h-6" /> : <Menu className="w-6 h-6" />}
            </button>
          </div>
        </div>
      </div>

      {/* Mobile Menu */}
      {isOpen && (
        <div className="md:hidden bg-white border-t border-slate-100 animate-in slide-in-from-top-4">
          <div className="px-4 pt-2 pb-6 space-y-2">
            {navItems.map((item) => (
              <Link
                key={item.path}
                to={item.path}
                onClick={() => setIsOpen(false)}
                className="block px-3 py-4 text-base font-medium text-slate-700 border-b border-slate-50"
              >
                {item.name}
              </Link>
            ))}
            <div className="flex items-center space-x-4 py-4">
              {(['UZ', 'RU', 'EN'] as Language[]).map((l) => (
                <button
                  key={l}
                  onClick={() => { setLang(l); setIsOpen(false); }}
                  className={`text-sm font-bold px-3 py-1 rounded ${lang === l ? 'bg-indigo-600 text-white' : 'bg-slate-100 text-slate-500'}`}
                >
                  {l}
                </button>
              ))}
            </div>
            <Link
              to="/apply"
              onClick={() => setIsOpen(false)}
              className="block w-full text-center bg-indigo-600 text-white px-5 py-3 rounded-xl font-semibold"
            >
              {t.nav.apply}
            </Link>
          </div>
        </div>
      )}
    </nav>
  );
};

