import { Search, Filter, Sparkles } from 'lucide-react';
import { geminiService } from '../services/geminiService';

interface JobsProps {
  lang: Language;
}

const Jobs: React.FC<JobsProps> = ({ lang }) => {
  const [searchTerm, setSearchTerm] = useState('');
  const [activeFilter, setActiveFilter] = useState('All');
  const [aiAdvice, setAiAdvice] = useState<string | null>(null);
  const [loadingAi, setLoadingAi] = useState(false);

  const t = TRANSLATIONS[lang];

  const filteredJobs = MOCK_JOBS.filter(job => {
    const matchesSearch = job.title[lang].toLowerCase().includes(searchTerm.toLowerCase()) ||
                          job.country[lang].toLowerCase().includes(searchTerm.toLowerCase());
    const matchesFilter = activeFilter === 'All' || job.category[lang] === activeFilter;
    return matchesSearch && matchesFilter;
  });

  const categories = ['All', ...new Set(MOCK_JOBS.map(j => j.category[lang]))];

  const getAiHelp = async () => {
    setLoadingAi(true);
    const advice = await geminiService.getCareerAdvice("What skills are most in demand for jobs in Germany and Poland for Uzbek workers?", lang);
    setAiAdvice(advice || null);
    setLoadingAi(false);
  };

  return (
    <div className="pt-32 pb-24 bg-slate-50 min-h-screen">
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="mb-12">
          <h1 className="text-4xl lg:text-5xl font-display font-extrabold text-slate-900 mb-6">{t.nav.jobs}</h1>

          {/* AI Helper Card */}
          <div className="bg-gradient-to-r from-indigo-900 to-indigo-800 rounded-3xl p-8 mb-10 text-white shadow-2xl shadow-indigo-200 relative overflow-hidden">
            <div className="absolute top-0 right-0 p-8 opacity-10">
              <Sparkles className="w-32 h-32" />
            </div>
            <div className="relative z-10 flex flex-col md:flex-row items-center justify-between gap-6">
              <div className="max-w-2xl">
                <h3 className="text-2xl font-bold mb-3 flex items-center">
                  <Sparkles className="w-6 h-6 mr-2 text-indigo-400" />
                  AI Karera maslahatchisi
                </h3>
                <p className="text-indigo-100 mb-4">
                  Qaysi davlat yoki soha sizga ko'proq mos kelishini bilmayapsizmi? AI yordamchimizdan so'rang!
                </p>
                {aiAdvice && (
                  <div className="bg-white/10 backdrop-blur p-4 rounded-2xl text-sm border border-white/10 mb-4 animate-in fade-in duration-500">
                    {aiAdvice}
                  </div>
                )}
              </div>
              <button 
                onClick={getAiHelp}
                disabled={loadingAi}
                className="whitespace-nowrap bg-white text-indigo-900 px-8 py-4 rounded-2xl font-bold hover:bg-indigo-50 transition-all flex items-center"
              >
                {loadingAi ? 'O\'ylanmoqda...' : 'Maslahat olish'}
              </button>
            </div>
          </div>

          {/* Search & Filters */}
          <div className="grid md:grid-cols-3 gap-6 items-center">
            <div className="md:col-span-2 relative">
              <Search className="absolute left-4 top-1/2 -translate-y-1/2 text-slate-400 w-5 h-5" />
              <input 
                type="text" 
                placeholder="Davlat yoki kasb bo'yicha qidiruv..."
                className="w-full pl-12 pr-4 py-4 rounded-2xl border border-slate-200 focus:outline-none focus:ring-2 focus:ring-indigo-500 focus:border-transparent transition-all shadow-sm"
                value={searchTerm}
                onChange={(e) => setSearchTerm(e.target.value)}
              />
            </div>
            <div className="flex items-center space-x-2 overflow-x-auto pb-2 md:pb-0 scrollbar-hide">
              <Filter className="w-5 h-5 text-slate-400 flex-shrink-0" />
              {categories.map(cat => (
                <button
                  key={cat}
                  onClick={() => setActiveFilter(cat)}
                  className={`px-5 py-2 rounded-full whitespace-nowrap text-sm font-semibold transition-all ${activeFilter === cat ? 'bg-indigo-600 text-white' : 'bg-white text-slate-600 border border-slate-200 hover:border-indigo-300'}`}
                >
                  {cat === 'All' ? t.filters.all : cat}
                </button>
              ))}
