                onClick={() => {setSearchTerm(''); setActiveFilter('All');}}
                className="text-indigo-600 font-black hover:underline text-lg"
              >
                Filtrlarni tozalash
              </button>
            </div>
          )}
        </div>
      </div>
    </div>
  );
};

export default Jobs;

