import { TRANSLATIONS } from '../constants';
import { useGlobal } from '../GlobalContext';

const Navbar: React.FC = () => {
  const { lang, setLang, theme, toggleTheme } = useGlobal();
  const [isOpen, setIsOpen] = useState(false);
  const [scrolled, setScrolled] = useState(false);
  const location = useLocation();
  const t = TRANSLATIONS[lang];

  useEffect(() => {
    const handleScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', handleScroll);
    return () => window.removeEventListener('scroll', handleScroll);
  }, []);

  const navItems = [
    { name: t.nav.home, path: '/' },
    { name: t.nav.jobs, path: '/jobs' },
    { name: t.nav.about, path: '/about' },
    { name: t.nav.partners, path: '/partners' },
    { name: t.nav.contact, path: '/contact' },
    // Fix: Using translated 'chat' label
    { name: t.nav.chat, path: '/career-advisor', icon: <MessageSquare className="w-4 h-4" /> },
  ];

  return (
    <nav className={`fixed top-0 left-0 right-0 z-50 transition-all duration-300 ${
      scrolled 
        ? 'bg-white/80 dark:bg-slate-900/80 backdrop-blur-md shadow-sm py-3' 
        : 'bg-transparent py-5'
    }`}>
      <div className="max-w-7xl mx-auto px-4 sm:px-6 lg:px-8">
        <div className="flex justify-between items-center">
          <Link to="/" className="flex items-center space-x-2">
            <span className={`text-2xl font-display font-extrabold tracking-tighter ${
              scrolled || theme === 'dark' ? 'text-indigo-600' : 'text-indigo-800'
            }`}>IMKON</span>
          </Link>

          {/* Desktop Nav */}
          <div className="hidden md:flex items-center space-x-6">
            {navItems.map((item) => (
              <Link 
                key={item.path} 
                to={item.path}
                className={`text-sm font-semibold transition-colors flex items-center space-x-1 ${
                  location.pathname === item.path 
                    ? 'text-indigo-600' 
                    : 'text-slate-600 dark:text-slate-300 hover:text-indigo-500'
                }`}
              >
                {item.icon && item.icon}
                <span>{item.name}</span>
              </Link>
            ))}
          </div>

          <div className="hidden md:flex items-center space-x-4">
            {/* Theme Toggle */}
            <button 
              onClick={toggleTheme}
              className="p-2 rounded-xl bg-slate-100 dark:bg-slate-800 text-slate-600 dark:text-slate-300 hover:bg-indigo-100 dark:hover:bg-indigo-900/30 transition-all"
