                <button
                  key={l}
                  onClick={() => setLang(l)}
                  className={`text-[10px] font-black px-2 py-1 rounded-lg transition-all ${
                    lang === l ? 'bg-indigo-600 text-white' : 'text-slate-500 dark:text-slate-400 hover:bg-slate-100 dark:hover:bg-slate-800'
                  }`}
                >
                  {l}
