import React, { createContext, useContext, useState, useEffect } from 'react';
import { Language, Theme, Job, SiteInfo, Application } from './types';
import { MOCK_JOBS } from './constants';

interface GlobalContextType {
  lang: Language;
  setLang: (l: Language) => void;
  theme: Theme;
  toggleTheme: () => void;
  jobs: Job[];
  setJobs: React.Dispatch<React.SetStateAction<Job[]>>;
  siteInfo: SiteInfo;
  setSiteInfo: React.Dispatch<React.SetStateAction<SiteInfo>>;
  applications: Application[];
  addApplication: (app: Omit<Application, 'id' | 'createdAt' | 'status'>) => void;
  updateApplicationStatus: (id: string, status: Application['status']) => void;
}

const GlobalContext = createContext<GlobalContextType | undefined>(undefined);

export const GlobalProvider: React.FC<{ children: React.ReactNode }> = ({ children }) => {
  // Load language from localStorage if exists
  const [lang, setLangInternal] = useState<Language>(() => {
    const saved = localStorage.getItem('imkon_lang');
    return (saved as Language) || 'UZ';
  });

  const [theme, setTheme] = useState<Theme>(() => {
    const saved = localStorage.getItem('imkon_theme');
    return (saved as Theme) || 'light';
  });

  const [jobs, setJobs] = useState<Job[]>(MOCK_JOBS);
  const [applications, setApplications] = useState<Application[]>([]);
  const [siteInfo, setSiteInfo] = useState<SiteInfo>({
    heroTitle: {
      UZ: "Biz sizni uzoqroqqa olib boramiz",
      RU: "Мы ведем вас дальше",
      EN: "We take you further"
    },
    heroSubtitle: {
      UZ: "Yevropa va butun dunyo bo'ylab rasmiy va ishonchli ish o'rinlari.",
      RU: "Официальное и надежное трудоустройство в Европе и по всему миру.",
      EN: "Official and reliable job opportunities across Europe and the world."
    },
    phone: "+998 71 234 56 78",
    email: "info@imkon.uz",
    address: "Toshkent sh., Chilonzor tumani, Bunyodkor ko'chasi, 42-uy"
  });

  useEffect(() => {
    document.documentElement.classList.toggle('dark', theme === 'dark');
    localStorage.setItem('imkon_theme', theme);
  }, [theme]);

  const setLang = (l: Language) => {
    setLangInternal(l);
    localStorage.setItem('imkon_lang', l);
  };

  const toggleTheme = () => setTheme(prev => prev === 'light' ? 'dark' : 'light');

  const addApplication = (appData: Omit<Application, 'id' | 'createdAt' | 'status'>) => {
    const newApp: Application = {
      ...appData,
      id: Math.random().toString(36).substr(2, 9),
      createdAt: new Date().toISOString().split('T')[0],
      status: 'pending'
    };
    setApplications(prev => [newApp, ...prev]);
  };

  const updateApplicationStatus = (id: string, status: Application['status']) => {
    setApplications(prev => prev.map(a => a.id === id ? { ...a, status } : a));
  };

  return (
    <GlobalContext.Provider value={{ 
      lang, setLang, theme, toggleTheme, jobs, setJobs, siteInfo, setSiteInfo, applications, addApplication, updateApplicationStatus 
    }}>
      {children}
    </GlobalContext.Provider>
  );
};

export const useGlobal = () => {
  const context = useContext(GlobalContext);
  if (!context) throw new Error('useGlobal must be used within GlobalProvider');
  return context;
};

